	public static boolean isSatisfiableZ3(IRestrictionTerm r) {

		// context for the Z3 solver
		Map<String, String> solverSettings = new HashMap<String, String>();
		solverSettings.put("unsat_core", "false");
		solverSettings.put("timeout", Integer.toString(Z3Timeout * 1000));

		Context context = null;
		context = new Context(solverSettings);

		// Z3 Solver
		Optimize solver;

		// empty restriction term
		if(r == null) {
			return true;
		}

		BoolExpr r_inZ3format = toZ3(context, r);
		solver = context.mkOptimize();
		solver.Add(r_inZ3format);

		Status check = solver.Check();

		if(check == SATISFIABLE)
			return true;

		return false;
	}

The toZ3 method above is used to convert our internal representation of propositional logic formulas into Z3's representation. It uses the mk... methods in the context to build the objects that compose the formula.

